use std::process::Command;
use std::io::{self, Write};

/// Execute a system command and return the output
/// 
/// # Arguments
/// 
/// * `command` - A string slice that holds the command to execute
/// 
/// # Returns
/// 
/// * `Result<String, String>` - Ok with stdout if successful, Err with error message otherwise
pub fn execute_command(command: &str) -> Result<String, String> {
    let output = Command::new("sh")
        .arg("-c")
        .arg(command)
        .output();

    match output {
        Ok(output) => {
            if output.status.success() {
                let stdout = String::from_utf8_lossy(&output.stdout);
                Ok(stdout.to_string())
            } else {
                let stderr = String::from_utf8_lossy(&output.stderr);
                Err(stderr.to_string())
            }
        }
        Err(e) => Err(format!("Failed to execute command: {}", e)),
    }
}

/// Execute a system command with verbose output
/// 
/// # Arguments
/// 
/// * `command` - A string slice that holds the command to execute
/// 
/// # Returns
/// 
/// * `Result<(String, String, i32), String>` - Ok with (stdout, stderr, exit_code) if successful, Err with error message otherwise
pub fn execute_command_detailed(command: &str) -> Result<(String, String, i32), String> {
    let output = Command::new("sh")
        .arg("-c")
        .arg(command)
        .output();

    match output {
        Ok(output) => {
            let stdout = String::from_utf8_lossy(&output.stdout).to_string();
            let stderr = String::from_utf8_lossy(&output.stderr).to_string();
            let exit_code = output.status.code().unwrap_or(-1);

            if output.status.success() {
                Ok((stdout, stderr, exit_code))
            } else {
                Err(format!("Command failed with exit code {}: {}", exit_code, stderr))
            }
        }
        Err(e) => Err(format!("Failed to execute command: {}", e)),
    }
}

